const root = window.parent ?? window;
const INSTANCE_KEY = '__YUZI_PHONE_INSTANCE__';
const LEGACY_TRACE_IDS = [
  'yuzi-phone-root',
  'yuzi-phone-standalone',
  'yuzi-phone-toggle',
  'yuzi-phone-settings',
  'yuzi-phone-css',
  'yuzi-phone-js',
];

function getRootDocument() {
  return root?.document ?? document;
}

function findBlockingTraceId() {
  const doc = getRootDocument();
  if (!doc?.querySelector) return '';
  return LEGACY_TRACE_IDS.find(id => doc.querySelector('#' + id)) || '';
}

function getDuplicateLoadBlockReason() {
  return root?.[INSTANCE_KEY] ? INSTANCE_KEY : findBlockingTraceId();
}

function notifyDuplicateLoadBlocked(reason) {
  const message = '[玉子手机] 检测到已加载实例或旧痕迹，已阻止重复加载';
  console.warn(message, reason);
  try {
    if (typeof root.alert === 'function') {
      root.alert('检测到玉子手机已加载，请勿同时启用扩展版和脚本版。');
    }
  } catch {}
}

const initialBlockReason = getDuplicateLoadBlockReason();
if (initialBlockReason) {
  notifyDuplicateLoadBlocked(initialBlockReason);
} else {
  async function getLatestVersion() {
    try {
      const res = await fetch('https://api.github.com/repos/yuzi83/st-yuzi-phone/tags');
      const tags = await res.json();
      return tags[0]?.name || 'v1.4.2';
    } catch {
      return 'v1.4.2';
    }
  }

  const version = await getLatestVersion();
  const postFetchBlockReason = getDuplicateLoadBlockReason();
  if (postFetchBlockReason) {
    notifyDuplicateLoadBlocked(postFetchBlockReason);
  } else {
    const base = `https://gcore.jsdelivr.net/gh/yuzi83/st-yuzi-phone@${version}`;

    if (!root.document.querySelector('#yuzi-phone-css')) {
      const link = root.document.createElement('link');
      link.id = 'yuzi-phone-css';
      link.rel = 'stylesheet';
      link.href = `${base}/dist/yuzi-phone.bundle.css`;
      root.document.head.appendChild(link);
    }

    if (!root.document.querySelector('#yuzi-phone-js')) {
      const script = root.document.createElement('script');
      script.id = 'yuzi-phone-js';
      script.type = 'module';
      script.src = `${base}/dist/yuzi-phone.bundle.js`;
      root.document.head.appendChild(script);
    }
  }
}
